// Recolectar todas las predicciones de las 5 ramas
const items = $input.all();
const todasLasPredicciones = [];

// Cada entrada del input es un array de items de una rama
// Los inputs vienen en orden: Futbol, Baloncesto, MLB, NHL, NFL
for (const branchItems of items) {
  // branchItems puede ser un array si la rama tiene múltiples items
  if (Array.isArray(branchItems)) {
    for (const item of branchItems) {
      if (item && item.json) {
        todasLasPredicciones.push(item.json);
      }
    }
  } else if (branchItems && branchItems.json) {
    todasLasPredicciones.push(branchItems.json);
  }
}

// Devolver todas las predicciones como items separados
return todasLasPredicciones.map(p => ({ json: p }));

// Filtrar predicciones destacadas de todas las recolectadas
const items = $input.all();
const destacadas = [];

for (const item of items) {
  const riesgo = item.json.Riesgo;
  const prob = parseFloat(item.json.Probabilidad_Victoria);
  if (riesgo === 'Bajo' && prob > 70) {
    destacadas.push(item);
  }
}

return destacadas;

const destacadas = $input.all();

if (destacadas.length === 0) {
  return [{ json: { message: '✅ No se encontraron apuestas destacadas hoy.' } }];
}

let mensaje = '🔥 *APUESTAS DESTACADAS DEL DÍA* 🔥\n\n';

for (let i = 0; i < destacadas.length; i++) {
  const d = destacadas[i].json;
  mensaje += `*${i + 1}. ${d.Evento}*\n`;
  mensaje += `📊 Liga: ${d.Liga_Categoria}\n`;
  mensaje += `📈 Probabilidad: ${d.Probabilidad_Victoria}% | Riesgo: ${d.Riesgo}\n`;
  mensaje += `⚽ Predicción: ${d.Prediccion_Marcador}\n`;
  mensaje += `💡 ${d.Justificacion_Clave}\n\n`;
}

mensaje += '---\n🤖 Reporte generado automáticamente por IA Deportiva';

return [{ json: { message: mensaje } }];
